 62→  "data-cy-row"?: string;
 63→  "data-cy-table"?: string;
 64→  emptyComponent?: React.ReactNode;
 65→  loading?: boolean;
 66→  /** estimated number of rows the table will have */
 67→  loadingRows?: number;
 68→  /** number of total items the table will have */
 69→  numTotalItems?: number;
 70→  /** rows that will have a blue tint to represent that they are selected */
 71→  selectedRowIndexes?: number[];
 72→  /** rows that will have a disabled style */
 73→  disabledRowIndexes?: number[];
 74→  /** whether the table is paginated */
 75→  usePagination?: boolean;
 76→  /** Object returned from the useLeafyGreenTable or useLeafyGreenVirtualTable hook */
 77→  table: LeafyGreenVirtualTable<T> | LeafyGreenTable<T>;
 78→  /** CSS to apply to the table rows */
 79→  rowCss?: SerializedStyles;
 80→}
 81→
 82→type BaseTableProps<T extends LGRowData = LGRowData> = SpruceTableProps<T> &
 83→  Omit<TableProps<T>, "table">;
 84→
 85→// eslint-disable-next-line @typescript-eslint/no-explicit-any
 86→export const BaseTable = forwardRef<HTMLDivElement, BaseTableProps<any>>(
 87→  <T extends LGRowData>(
 88→    {
 89→      "data-cy-row": dataCyRow,
 90→      "data-cy-table": dataCyTable,
 91→      disabledRowIndexes = [],
 92→      emptyComponent,
 93→      loading,
 94→      loadingRows = 5,
 95→      numTotalItems,
 96→      rowCss,
 97→      selectedRowIndexes = [],
 98→      table,
 99→      usePagination = false,
100→      verticalAlignment = "middle",
101→      ...args
102→    }: BaseTableProps<T>,
103→    ref: ForwardedRef<HTMLDivElement>,
104→  ) => {
105→    const { rows } = table.getRowModel();
106→
107→    const virtualRows = table.virtual?.getVirtualItems();
108→    const hasVirtualRows = virtualRows && virtualRows.length > 0;
109→
110→    return (
111→      <>
112→        <Table
113→          ref={ref}
114→          data-cy={dataCyTable}
115→          table={table}
116→          verticalAlignment={verticalAlignment}
117→          {...args}
118→        >
119→          <TableHead isSticky={hasVirtualRows}>
120→            {table.getHeaderGroups().map((headerGroup) => (
121→              <HeaderRow key={headerGroup.id}>
122→                {headerGroup.headers.map((header) => (
123→                  <TableHeaderCell
124→                    key={header.id}
125→                    header={header}
126→                    table={table}
127→                    usePagination={usePagination}
128→                  />
129→                ))}
130→              </HeaderRow>
131→            ))}
132→          </TableHead>
133→          <TableBody>
134→            {loading && (
135→              <TableLoader
136→                numColumns={table.getAllColumns().length}
137→                numRows={loadingRows}
138→              />
139→            )}
140→
141→            {hasVirtualRows
142→              ? virtualRows.map((vr) => {
143→                  const { row } = vr;
144→                  return (
145→                    <RenderableRow
146→                      key={row.id}
147→                      dataCyRow={dataCyRow}
148→                      disabled={disabledRowIndexes?.includes(row.index)}
149→                      isSelected={selectedRowIndexes.includes(row.index)}
150→                      row={row}
151→                      rowCss={rowCss}
152→                      virtualRow={vr}
153→                    />
154→                  );
155→                })
156→              : rows.map((row) => (
157→                  <RenderableRow
158→                    key={row.id}
159→                    dataCyRow={dataCyRow}
160→                    disabled={disabledRowIndexes?.includes(row.index)}
161→                    isSelected={selectedRowIndexes.includes(row.index)}
162→                    row={row}
163→                    rowCss={rowCss}
164→                  />
165→                ))}
166→          </TableBody>
167→        </Table>
168→        {!loading &&
169→          rows.length === 0 &&
170→          (emptyComponent || (
171→            <DefaultEmptyMessage>No data to display</DefaultEmptyMessage>
172→          ))}
173→        {usePagination && table && (
174→          <StyledPagination
175→            currentPage={table.getState().pagination.pageIndex + 1}
176→            itemsPerPage={table.getState().pagination.pageSize}
177→            numTotalItems={numTotalItems}
178→            onBackArrowClick={() => table.previousPage()}
179→            onCurrentPageOptionChange={(value: string) => {
180→              table.setPageIndex(Number(value) - 1);
181→            }}
182→            onForwardArrowClick={() => table.nextPage()}
183→            onItemsPerPageOptionChange={(value: string) => {
184→              table.setPageSize(Number(value));
185→            }}
186→          />
187→        )}
188→      </>
189→    );
190→  },
191→);
192→
193→BaseTable.displayName = "BaseTable";
194→
195→const TableHeaderCell = <T extends LGRowData>({
196→  header,
197→  table,
198→  usePagination,
199→}: {
200→  header: Header<LGTableDataType<T>, unknown>;
201→  table: LeafyGreenVirtualTable<T> | LeafyGreenTable<T>;
202→  usePagination: boolean;
203→}) => {
204→  const { columnDef } = header.column ?? {};
205→  const { meta } = columnDef;
206→  return (
207→    // eslint-disable-next-line @typescript-eslint/ban-ts-comment
208→    // @ts-ignore: This is a workaround to fix the type error
209→    <HeaderCell
210→      key={header.id}
211→      header={header}
212→      id={header.id}
213→      // @ts-expect-error: This is a workaround to fix the type error
214→      style={meta?.width && { width: meta.width }}
215→    >
216→      {flexRender(columnDef.header, header.getContext())}
217→      {header.column.getCanFilter() &&
218→        (meta?.treeSelect ? (
219→          <TableFilterPopover
220→            data-cy={meta.treeSelect?.["data-cy"]}
221→            onConfirm={(value) => {
222→              header.column.setFilterValue(value);
223→              if (usePagination) {
224→                table.firstPage();
225→              }
226→            }}
227→            options={
228→              meta.treeSelect?.filterOptions
229→                ? meta.treeSelect.options.filter(
230→                    ({ value }) =>
231→                      !!header.column.getFacetedUniqueValues().get(value),
232→                  )
233→                : meta.treeSelect.options
234→            }
235→            value={
236→              conditionalToArray(
237→                header?.column?.getFilterValue() ?? [],
238→                true,
239→              ) as string[]
240→            }
241→          />
242→        ) : (
243→          <TableSearchPopover
244→            data-cy={meta?.search?.["data-cy"]}
245→            onConfirm={(value) => {
246→              header.column.setFilterValue(value);
247→              if (usePagination) {
248→                table.firstPage();
249→              }
250→            }}
251→            placeholder={meta?.search?.placeholder}
252→            value={(header?.column?.getFilterValue() as string) ?? ""}
253→          />
254→        ))}
255→    </HeaderCell>
256→  );
257→};
258→
259→const cellPaddingStyle = {
260→  paddingBottom: size.xxs,
261→  paddingTop: size.xxs,
262→};
263→
264→const cellStyle = css`
265→  /* Force the nested div wrapping the cell content to take up full width. */
266→  > div > div > div {
267→    width: 100%;
268→  }
269→`;
270→
271→const RenderableRow = <T extends LGRowData>({
272→  dataCyRow = "leafygreen-table-row",
273→  disabled = false,
274→  isSelected = false,
275→  row,
276→  rowCss,
277→  virtualRow,
278→}: {
279→  dataCyRow?: string;
280→  row: LeafyGreenTableRow<T>;
281→  virtualRow?: VirtualItem;
282→  isSelected?: boolean;
283→  disabled?: boolean;
284→  rowCss?: SerializedStyles;
285→}) => (
286→  <Fragment key={row.id}>
287→    {!row.isExpandedContent && (
288→      // eslint-disable-next-line @typescript-eslint/ban-ts-comment
289→      // @ts-ignore: This is a workaround to fix the type error
290→      <Row
291→        className={css`
292→          ${rowCss}
293→          ${isSelected &&
294→          `
295→           background-color: ${blue.light3} !important;
296→           font-weight:bold;
297→           `}
298→        `}
299→        data-cy={dataCyRow}
300→        data-index={row.index}
301→        data-selected={isSelected}
302→        disabled={disabled}
303→        row={row}
304→        virtualRow={virtualRow}
305→      >
306→        {row.getVisibleCells().map((cell) => (
307→          // eslint-disable-next-line @typescript-eslint/ban-ts-comment
308→          // @ts-ignore: This is a workaround to fix the type error
309→          <Cell
310→            key={cell.id}
311→            cell={cell}
312→            className={cellStyle}
313→            style={cellPaddingStyle}
314→          >
315→            {flexRender(cell.column.columnDef.cell, cell.getContext())}
316→          </Cell>
317→        ))}
318→      </Row>
319→    )}
320→    {row.isExpandedContent && (
321→      <StyledExpandedContent row={row as LeafyGreenTableRow<unknown>} />
322→    )}
323→  </Fragment>
324→);
325→
326→const DefaultEmptyMessage = styled.div`
327→  margin-top: ${size.s};
328→  margin-left: ${tableColumnOffset};
329→`;
330→
331→const StyledExpandedContent = styled(
332→  ExpandedContent as React.ComponentType<ExpandedContentProps<LGRowData>>,
333→)`
334→  > td {
335→    padding: ${size.xs} 0;
336→    background-color: ${gray.light3};
337→  }
338→`;
339→
340→const StyledPagination = styled(Pagination)`
341→  margin-top: ${size.xs};
342→`;
